# -*- coding: utf-8 -*-
"""Tarea 2: Calculadora de expresiones restringidas.

La solución procesa cada comando caracter por caracter, sin usar
funciones de cadenas que trabajen sobre subcadenas completas.
"""

import sys


def _es_blanco(ch):
    return ch == " " or ch == "\t" or ch == "\n" or ch == "\r"


def _es_letra(ch):
    return ("a" <= ch <= "z") or ("A" <= ch <= "Z")


def _es_digito(ch):
    return "0" <= ch <= "9"


def _es_operador(ch):
    return ch == "+" or ch == "-" or ch == "*" or ch == "/" or ch == "^"


def _saltar_blancos(texto, indice):
    while indice < len(texto) and _es_blanco(texto[indice]):
        indice += 1
    return indice


def _subcadena_desde(texto, indice):
    resultado = ""
    while indice < len(texto):
        resultado += texto[indice]
        indice += 1
    return resultado


def _imprimir_error_sintaxis(texto, indice):
    print('ERROR: al procesar "' + _subcadena_desde(texto, indice) + '"')


def _imprimir_error_variable(nombre):
    print('ERROR: variable indefinida "' + nombre + '"')


def _div_entera_truncada(dividendo, divisor):
    if divisor == 0:
        raise ZeroDivisionError
    signo_negativo = (dividendo < 0) != (divisor < 0)
    cociente = abs(dividendo) // abs(divisor)
    if signo_negativo:
        return -cociente
    return cociente


def _parse_identificador(texto, indice):
    if indice >= len(texto) or not _es_letra(texto[indice]):
        return None, indice
    nombre = ""
    while indice < len(texto):
        ch = texto[indice]
        if _es_letra(ch) or _es_digito(ch) or ch == "_":
            nombre += ch
            indice += 1
        else:
            break
    return nombre, indice


def _parse_operando(texto, indice, dicc_var):
    indice = _saltar_blancos(texto, indice)
    if indice >= len(texto):
        return False, None, indice, "syntax", indice, None

    ch = texto[indice]
    if _es_digito(ch):
        valor = 0
        while indice < len(texto) and _es_digito(texto[indice]):
            valor = valor * 10 + (ord(texto[indice]) - ord("0"))
            indice += 1
        return True, valor, indice, None, None, None

    if _es_letra(ch):
        nombre, indice = _parse_identificador(texto, indice)
        if nombre in dicc_var:
            return True, dicc_var[nombre], indice, None, None, None
        return False, None, indice, "undef", None, nombre

    return False, None, indice, "syntax", indice, None


def _evaluar_expresion(texto, indice, dicc_var):
    ok, valor, indice, tipo_error, pos_error, nombre_error = _parse_operando(
        texto, indice, dicc_var
    )
    if not ok:
        return False, None, indice, tipo_error, pos_error, nombre_error

    while True:
        indice = _saltar_blancos(texto, indice)
        if indice >= len(texto):
            return True, valor, indice, None, None, None

        if not _es_operador(texto[indice]):
            return True, valor, indice, None, None, None

        operador = texto[indice]
        indice += 1
        ok, siguiente, indice, tipo_error, pos_error, nombre_error = _parse_operando(
            texto, indice, dicc_var
        )
        if not ok:
            return False, None, indice, tipo_error, pos_error, nombre_error

        if operador == "+":
            valor += siguiente
        elif operador == "-":
            valor -= siguiente
        elif operador == "*":
            valor *= siguiente
        elif operador == "/":
            valor = _div_entera_truncada(valor, siguiente)
        else:
            valor = valor ** siguiente


def procesar_comando(comando, dicc_var):
    indice = _saltar_blancos(comando, 0)
    if indice >= len(comando):
        return dicc_var

    nombre, indice_nombre = _parse_identificador(comando, indice)
    if nombre is None:
        _imprimir_error_sintaxis(comando, indice)
        return dicc_var

    indice = _saltar_blancos(comando, indice_nombre)
    if indice >= len(comando):
        if nombre in dicc_var:
            print(dicc_var[nombre])
        else:
            _imprimir_error_variable(nombre)
        return dicc_var

    if comando[indice] != "=":
        _imprimir_error_sintaxis(comando, indice)
        return dicc_var

    indice += 1
    ok, valor, indice, tipo_error, pos_error, nombre_error = _evaluar_expresion(
        comando, indice, dicc_var
    )
    if not ok:
        if tipo_error == "undef":
            _imprimir_error_variable(nombre_error)
        else:
            _imprimir_error_sintaxis(comando, pos_error)
        return dicc_var

    indice = _saltar_blancos(comando, indice)
    if indice < len(comando):
        _imprimir_error_sintaxis(comando, indice)
        return dicc_var

    dicc_var[nombre] = valor
    print(valor)
    return dicc_var


def calculadora(lista_comandos):
    dicc_var = {}
    for comando in lista_comandos:
        dicc_var = procesar_comando(comando, dicc_var)


if __name__ == "__main__":
    variables = {}
    for linea in sys.stdin:
        variables = procesar_comando(linea, variables)
